```python
def diff_dicts(dict1, dict2, path=""):
    """
    Recursively compare two dictionaries and return differences.
    Returns: dict with 'added', 'removed', 'changed', 'unchanged' keys
    """
    result = {
        'added': {},
        'removed': {},
        'changed': {},
        'unchanged': {}
    }

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        if key not in dict1:
            result['added'][current_path] = dict2[key]
        elif key not in dict2:
            result['removed'][current_path] = dict1[key]
        elif isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            # Recurse into nested dictionaries
            nested_diff = diff_dicts(dict1[key], dict2[key], current_path)
            for diff_type in ['added', 'removed', 'changed', 'unchanged']:
                if nested_diff[diff_type]:
                    result[diff_type].update(nested_diff[diff_type])
        elif dict1[key] == dict2[key]:
            result['unchanged'][current_path] = dict1[key]
        else:
            result['changed'][current_path] = {
                'old': dict1[key],
                'new': dict2[key]
            }

    return result


def diff_dicts_simple(dict1, dict2):
    """
    Simplified version - returns only actual differences.
    """
    differences = {}

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        if key not in dict1:
            differences[key] = {'action': 'added', 'value': dict2[key]}
        elif key not in dict2:
            differences[key] = {'action': 'removed', 'value': dict1[key]}
        elif isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            nested = diff_dicts_simple(dict1[key], dict2[key])
            if nested:
                differences[key] = {'action': 'modified', 'diff': nested}
        elif dict1[key] != dict2[key]:
            differences[key] = {
                'action': 'changed',
                'old': dict1[key],
                'new': dict2[key]
            }

    return differences
```

**Contoh Penggunaan:**

